const inp=$input.first().json||{};
const strs=[]; (function col(x){if(x==null)return;if(typeof x==='string'){strs.push(x);return;}if(typeof x==='object')for(const v of Object.values(x))col(v);})(inp);
function fs(x){if(x&&typeof x==='object'&&!Array.isArray(x)){if(x.ip!==undefined||x.indicator!==undefined||x.hash!==undefined||x.target!==undefined)return x;for(const v of Object.values(x)){const r=fs(v);if(r)return r;}}return null;}
const a=fs(inp)||{}; let ind=String(a.indicator||a.ip||a.hash||a.target||'').trim(); const all=strs.join(' ');
if(!ind){const ipm=all.match(/\b\d{1,3}(?:\.\d{1,3}){3}\b/);const hm=all.match(/\b[a-fA-F0-9]{64}\b|\b[a-fA-F0-9]{40}\b|\b[a-fA-F0-9]{32}\b/);ind=(ipm&&ipm[0])||(hm&&hm[0])||'';}
const isIP=/^\d{1,3}(\.\d{1,3}){3}$/.test(ind); const isHash=/^([a-fA-F0-9]{32}|[a-fA-F0-9]{40}|[a-fA-F0-9]{64})$/.test(ind);
return [{json:{indicator:ind, otype: isIP?'IPv4':(isHash?'file':'')}}];

const r=$input.first().json||{}; const code=(r.statusCode!==undefined)?r.statusCode:200; const body=(r.body!==undefined)?r.body:r;
const p=$('Parse').first().json||{}; const ind=p.indicator||''; const otype=p.otype||'';
if(!otype)return [{json:{indicator:ind,error:"OTX: indicateur non reconnu (ni IP ni hash md5/sha1/sha256)"}}];
if(code===404)return [{json:{indicator:ind,found:false,msg:"OTX: aucun enregistrement pour cet indicateur"}}];
if(code>=400)return [{json:{indicator:ind,error:"OTX HTTP "+code}}];
const b=body||{}; const pi=b.pulse_info||{};
return [{json:{indicator:ind, type:(otype==='IPv4'?'ip':'hash'), otx_pulses:(pi.count||0), signale_malveillant:((pi.count||0)>0), pulses_top:(pi.pulses||[]).slice(0,5).map(x=>x.name), reputation:(b.reputation!==undefined?b.reputation:null), pays:b.country_name||null, asn:b.asn||null, false_positive:((b.false_positive||[]).length>0)}}];
